sql:
SELECT hr, avnn
FROM hrv_data
WHERE hr = (SELECT MIN(hr) FROM hrv_data);

SELECT COUNT(artifact_id) AS total_artifacts_removed
FROM artifact_removal
WHERE removal_type = 'simple';

